    if (!auth) {
        initializeFirebase();
    }
    return auth;
};

const getFirebaseFirestore = () => {
    if (!db) {
        initializeFirebase();
    }
    return db;
};

const getFirebaseStorage = () => {
    if (!storage) {
        initializeFirebase();
    }
    return storage;
};

const getFirebaseFunctions = () => {
    if (!functions) {
        initializeFirebase();
    }
    return functions;
};

export {
    initializeFirebase,
    getFirebaseAuth,
    getFirebaseFirestore,
    getFirebaseStorage,
    getFirebaseFunctions,
    isConfigured,
};
]]></content>
