        onAuthSuccess(u);
        return;
      }

      if (auth.currentUser) {
          const u: User = {
              id: auth.currentUser.uid,
              email: auth.currentUser.email || '',
              businessName: formData.businessName,
              isVerified: true,
              subscriptionPlan: 'free'
          };
          onAuthSuccess(u);
      }
